package devmachine

import (
	"context"
	"fmt"
	"sync"
	"time"

	corev1 "k8s.io/api/core/v1"
	storagev1 "k8s.io/api/storage/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/util/wait"

	devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/external/k8s"
)

const (
	// PV/PVC 相关常量
	defaultStorageSize = "10Pi"
	storageClassName   = "tdsc-sc"
)

// CSIConfig 存储CSI相关信息
type CSIConfig struct {
	Driver            string                               `json:"driver"`
	SecretName        string                               `json:"secretName"`
	SecretNamespace   string                               `json:"secretNamespace"`
	JuiceFSImage      string                               `json:"juicefsImage"`
	MountOptions      []string                             `json:"mountOptions"`
	Parameters        map[string]string                    `json:"parameters"`
	ReclaimPolicy     corev1.PersistentVolumeReclaimPolicy `json:"reclaimPolicy"`
	VolumeBindingMode storagev1.VolumeBindingMode          `json:"volumeBindingMode"`
}

var (
	csiConfig   *CSIConfig
	configMutex sync.RWMutex
)

// GetCSIConfig 获取当前的CSI配置
func GetCSIConfig() *CSIConfig {
	configMutex.RLock()
	defer configMutex.RUnlock()
	return csiConfig
}

// SetCSIConfig 设置CSI配置
func SetCSIConfig(config *CSIConfig) {
	configMutex.Lock()
	defer configMutex.Unlock()
	csiConfig = config
}

// StartCSISyncLoop 启动CSI配置同步循环
func StartCSISyncLoop(k8sClient k8s.Client) {
	// 使用wait.Until启动定时同步循环
	go wait.Until(func() {
		// 获取StorageClass信息
		sc, err := getStorageClassInfo(k8sClient, storageClassName)
		if err != nil {
			// 记录错误但继续运行
			return
		}
		// 更新CSI配置
		SetCSIConfig(sc)
	}, 30*time.Second, wait.NeverStop)
}

// getStorageClassInfo 从k8s获取StorageClass信息并转换为CSIConfig
func getStorageClassInfo(k8sClient k8s.Client, className string) (*CSIConfig, error) {
	ctx := context.Background()
	if k8sClient == nil {
		return nil, fmt.Errorf("k8s client is nil")
	}
	sc, err := k8sClient.GetStorageClass(ctx, className)
	if err != nil {
		return nil, fmt.Errorf("failed to get storage class %s: %w", className, err)
	}

	config := &CSIConfig{
		Driver:            sc.Provisioner,
		ReclaimPolicy:     *sc.ReclaimPolicy,
		VolumeBindingMode: *sc.VolumeBindingMode,
		Parameters:        make(map[string]string),
		MountOptions:      make([]string, len(sc.MountOptions)),
	}

	// 复制参数
	for k, v := range sc.Parameters {
		config.Parameters[k] = v
	}

	// 复制挂载选项
	copy(config.MountOptions, sc.MountOptions)

	// 从参数中提取 Secret 信息
	if secretName, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-name"]; exists {
		config.SecretName = secretName
	}
	if secretNamespace, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-namespace"]; exists {
		config.SecretNamespace = secretNamespace
	}
	if juiceFSImage, exists := config.Parameters["juicefs/mount-image"]; exists {
		config.JuiceFSImage = juiceFSImage
	}

	return config, nil
}

// SyncCSIConfigFromStorageClass 从StorageClass同步CSI配置
func SyncCSIConfigFromStorageClass(k8sClient k8s.Client) error {
	sc, err := getStorageClassInfo(k8sClient, storageClassName)
	if err != nil {
		return fmt.Errorf("failed to get storage class info: %w", err)
	}
	SetCSIConfig(sc)
	return nil
}

// ==================== 共享存储构建 ====================

// buildSharedPV 构建共享 PersistentVolume
// 使用集群级别共享 PV，ReclaimPolicy 为 Retain（区别于旧的 Delete）
func buildSharedPV(name, subPath string, readOnly bool) (*corev1.PersistentVolume, error) {
	configMutex.RLock()
	defer configMutex.RUnlock()

	if csiConfig == nil {
		return nil, fmt.Errorf("CSI config not initialized, cannot build shared PV %s", name)
	}

	accessMode := corev1.ReadWriteMany
	if readOnly {
		accessMode = corev1.ReadOnlyMany
	}

	volumeMode := corev1.PersistentVolumeFilesystem
	pv := &corev1.PersistentVolume{
		ObjectMeta: metav1.ObjectMeta{
			Name: name,
		},
		Spec: corev1.PersistentVolumeSpec{
			Capacity: corev1.ResourceList{
				corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
			},
			VolumeMode:                    &volumeMode,
			AccessModes:                   []corev1.PersistentVolumeAccessMode{accessMode},
			PersistentVolumeReclaimPolicy: corev1.PersistentVolumeReclaimRetain,
			PersistentVolumeSource: corev1.PersistentVolumeSource{
				CSI: &corev1.CSIPersistentVolumeSource{
					Driver: csiConfig.Driver,
					FSType: "juicefs",
					NodePublishSecretRef: &corev1.SecretReference{
						Name:      csiConfig.SecretName,
						Namespace: csiConfig.SecretNamespace,
					},
					VolumeHandle:     name,
					VolumeAttributes: map[string]string{},
				},
			},
		},
	}

	if csiConfig.MountOptions != nil {
		pv.Spec.MountOptions = csiConfig.MountOptions
	}
	for k, v := range csiConfig.Parameters {
		pv.Spec.CSI.VolumeAttributes[k] = v
	}
	if subPath != "" {
		pv.Spec.CSI.VolumeAttributes["subPath"] = subPath
	}

	return pv, nil
}

// buildSharedPVC 构建 namespace 级共享 PersistentVolumeClaim
// 通过 spec.volumeName 显式绑定到集群共享 PV
func buildSharedPVC(namespace, pvcName, pvName string, readOnly bool) *corev1.PersistentVolumeClaim {
	accessMode := corev1.ReadWriteMany
	if readOnly {
		accessMode = corev1.ReadOnlyMany
	}

	storageClass := ""
	return &corev1.PersistentVolumeClaim{
		ObjectMeta: metav1.ObjectMeta{
			Name:      pvcName,
			Namespace: namespace,
		},
		Spec: corev1.PersistentVolumeClaimSpec{
			VolumeName:       pvName,
			AccessModes:      []corev1.PersistentVolumeAccessMode{accessMode},
			StorageClassName: &storageClass,
			Resources: corev1.VolumeResourceRequirements{
				Requests: corev1.ResourceList{
					corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
				},
			},
		},
	}
}

// buildSharedVolumes 根据 storage 列表构建共享卷（去重，最多 2 个）
// ReadOnly=false 的 storage 共用 shared-rw-volume
// ReadOnly=true  的 storage 共用 shared-ro-volume
func buildSharedVolumes(storages []devmachinemodel.Storage) []corev1.Volume {
	if len(storages) == 0 {
		return nil
	}

	volumes := make([]corev1.Volume, 0, 2)
	hasRW, hasRO := false, false

	for _, s := range storages {
		if !s.ReadOnly && !hasRW {
			hasRW = true
			volumes = append(volumes, corev1.Volume{
				Name: SharedRWVolumeName,
				VolumeSource: corev1.VolumeSource{
					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
						ClaimName: SharedRWPVCName,
					},
				},
			})
		}
		if s.ReadOnly && !hasRO {
			hasRO = true
			volumes = append(volumes, corev1.Volume{
				Name: SharedROVolumeName,
				VolumeSource: corev1.VolumeSource{
					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
						ClaimName: SharedROPVCName,
						ReadOnly:  true,
					},
				},
			})
		}
	}

	return volumes
}

// buildSharedVolumeMounts 构建共享卷挂载列表（每条 storage 独立挂载，subPath 隔离）
func buildSharedVolumeMounts(storages []devmachinemodel.Storage) []corev1.VolumeMount {
	if len(storages) == 0 {
		return nil
	}

	mounts := make([]corev1.VolumeMount, 0, len(storages))
	for _, s := range storages {
		volName := SharedRWVolumeName
		if s.ReadOnly {
			volName = SharedROVolumeName
		}
		mounts = append(mounts, corev1.VolumeMount{
			Name:      volName,
			MountPath: s.MountPath,
			SubPath:   s.StoragePath,
			ReadOnly:  s.ReadOnly,
		})
	}

	return mounts
}

package devmachine

// WebIDE类型
type WebIDEType string

const (
	WebIDEJupyter WebIDEType = "jupyter"
	WebIDEVSCode  WebIDEType = "vscode"

	RewriteTarget = "nginx.ingress.kubernetes.io/rewrite-target"
)

// CreatePodRequest 创建 Pod 请求
type CreatePodRequest struct {
	// Pod 名称
	Name string `json:"name" binding:"required" example:"my-pod"`
	// 容器镜像
	Image string `json:"image" binding:"required" example:"nginx:latest"`
	// 容器启动命令
	Command []string `json:"command" example:"nginx,-g,daemon off"`
	// 容器启动参数
	Args []string `json:"args" example:"-c,/etc/nginx/nginx.conf"`
	// 环境变量，键值对形式，例如: {"ENV1": "value1", "ENV2": "value2"}
	Env map[string]string `json:"env" swaggertype:"object,string" example:"ENV1:value1,ENV2:value2"`
	// 资源需求
	Resources *ResourceRequirements `json:"resources"`
	// Pod 标签，键值对形式，例如: {"app": "nginx", "env": "prod"}
	Labels map[string]string `json:"labels" swaggertype:"object,string" example:"app:nginx,env:prod"`
}

// ResourceRequirements 资源需求
type ResourceRequirements struct {
	// CPU 请求量，例如: "100m", "1"
	CPURequest string `json:"cpuRequest" example:"100m"`
	// CPU 限制量，例如: "200m", "2"
	CPULimit string `json:"cpuLimit" example:"200m"`
	// 内存请求量，例如: "128Mi", "1Gi"
	MemoryRequest string `json:"memoryRequest" example:"128Mi"`
	// 内存限制量，例如: "256Mi", "2Gi"
	MemoryLimit string `json:"memoryLimit" example:"256Mi"`
}

// DeletePodRequest 删除 Pod 请求
type DeletePodRequest struct {
	Name string `json:"name" binding:"required"`
}

// GetPodRequest 获取 Pod 请求
type GetPodRequest struct {
	Name string `json:"name" binding:"required"`
}

// ListPodsRequest 列出 Pod 请求
// @Description 列出 Pod 的请求参数，用于按标签过滤
type ListPodsRequest struct {
	// Pod 标签过滤器，键值对形式，例如: {"app": "nginx", "env": "prod"}
	Labels map[string]string `json:"labels" swaggertype:"object,string" example:"app:nginx,env:prod"`
}

// GetPodLogsRequest 获取 Pod 日志请求
type GetPodLogsRequest struct {
	Name      string `json:"name" binding:"required"`
	TailLines int64  `json:"tailLines"`
}

// CreateDevmachineRequest 创建 Devmachine 请求
type CreateDevmachineRequest struct {
	// 命名空间
	Namespace string `json:"namespace" binding:"required"`
	// Devmachine 名称
	Name string `json:"name" binding:"required"`
	// 容器镜像名称
	ImageName string `json:"imageName" binding:"required"`
	// 容器镜像标签
	Labels map[string]string `json:"labels"`
	// 容器镜像注释
	Annotations map[string]string `json:"annotations"`
	// 队列名称
	QueueName string `json:"queueName"`
	// CPU 资源需求
	CPU string `json:"cpu"`
	// 内存资源需求
	Memory string `json:"memory"`
	// GPU 资源需求
	GPU string `json:"gpu"`
	// GPU 名称
	GPUName string `json:"gpuName"`
	// WebIDE
	WebIDE WebIDEType `json:"webIDE" example:"jupyter | vscode"`
	// 默认工作目录
	WorkDir string `json:"workDir,omitempty" example:"tap-edu"`
	// 存储
	Storage []Storage `json:"storage"`
	// 节点选择器
	NodeSelector map[string]string `json:"nodeSelector,omitempty"`
}

type Storage struct {
	// 存储路径
	StoragePath string `json:"storagePath"`
	// 挂载路径
	MountPath string `json:"mountPath"`
	// 是否只读
	ReadOnly bool `json:"readOnly,omitempty"`
}

// UpdateDevmachineRequest 更新 Devmachine 请求
type UpdateDevmachineRequest struct {
	// 命名空间
	Namespace string `json:"namespace" binding:"required"`
	// Devmachine 名称
	Name string `json:"name" binding:"required"`
	// 容器镜像名称
	ImageName string `json:"imageName" binding:"required"`
	// 容器镜像标签
	Labels map[string]string `json:"labels"`
	// 容器镜像注释
	Annotations map[string]string `json:"annotations"`
	// 队列名称
	QueueName string `json:"queueName"`
	// CPU 资源需求
	CPU string `json:"cpu"`
	// 内存资源需求
	Memory string `json:"memory"`
	// GPU 资源需求
	GPU string `json:"gpu"`
	// GPU 名称
	GPUName string `json:"gpuName"`
	// WebIDE
	WebIDE WebIDEType `json:"webIDE" example:"jupyter | vscode"`
	// 默认工作目录
	WorkDir string `json:"workDir,omitempty" example:"tap-edu"`
	// 存储
	Storage []Storage `json:"storage"`
	// 节点选择器
