406	// BuildResourceRequirements 构建资源请求和限制
407	func BuildResourceRequirements(cpu, memory, gpu, gpuName string) corev1.ResourceRequirements {
408		requests := corev1.ResourceList{}
409		limits := corev1.ResourceList{}
410	
411		// 设置 CPU 请求
412		if cpu != "" {
413			cpuQuantity, err := resource.ParseQuantity(cpu + "") // 用户传入的数值，单位为核
414			if err == nil {
415				requests[corev1.ResourceCPU] = cpuQuantity
416				limits[corev1.ResourceCPU] = cpuQuantity
417			}
418		}
419	
420		// 设置内存请求
421		if memory != "" {
422			memoryQuantity, err := resource.ParseQuantity(memory + "Gi") // 用户传入的数值，单位为Gi
423			if err == nil {
424				requests[corev1.ResourceMemory] = memoryQuantity
425				limits[corev1.ResourceMemory] = memoryQuantity
426			}
427		}
428	
429		// 设置 GPU 请求
430		if gpu != "" && gpuName != "" {
431			gpuQuantity, err := resource.ParseQuantity(gpu) // GPU 数量
432			if err == nil {
433				// 检查 GPU 是否为虚拟化类型
434				if resourcesvc.IsGPUResource(gpuName) && resourcesvc.GetGPUType(gpuName) == resourcesvc.GPUCardTypeVirtual {
435					// 如果是虚拟化 GPU，需要特殊处理
436					requests[corev1.ResourceName(gpuName)] = gpuQuantity
437					limits[corev1.ResourceName(gpuName)] = gpuQuantity
438					//
439	
440				} else {
441					// 如果是整卡 GPU，直接设置
442					requests[corev1.ResourceName(gpuName)] = gpuQuantity
443					limits[corev1.ResourceName(gpuName)] = gpuQuantity
444				}
445			}
446		}
447	
448		return corev1.ResourceRequirements{
449			Requests: requests,
450			Limits:   limits,
451		}
452	}
