518	func generateVSCodeIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
519		labels := generateLabels(request.Namespace, request.Name, request.Labels)
520		port := getServicePort(devmachinemodel.WebIDEVSCode)
521		basePath := buildIngressPath(request.Namespace, request.Name)
522		path := fmt.Sprintf("%s(/|$)(.*)", basePath)
523	
524		annotations := defaultAnnotations
525		annotations[devmachinemodel.RewriteTarget] = "/$2"
526	
527		ingress := &networkingv1.Ingress{
528			ObjectMeta: metav1.ObjectMeta{
529				Name:        request.Name + ingressSuffix,
530				Namespace:   request.Namespace,
531				Labels:      labels,
532				Annotations: annotations,
533			},
534			Spec: buildIngressSpec(request.Name+serviceSuffix, path, port),
535		}
