94	func (s *service) CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error) {
95		// 验证请求参数
96		if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
97			return nil, NewValidationError("devmachine", request.Name, err)
98		}
99	
100		var err error
101	
102		defer func() {
103			if err != nil {
104				log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
105				_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
106			}
107		}()
108	
109		// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
110		// TODO: 新环境稳定后可移除此兼容逻辑
111		if len(request.Storage) > 0 {
112			if err = s.ensureSharedPVCs(ctx, request.Namespace, request.Storage); err != nil {
113				return nil, err
114			}
115		}
116	
117		// 3. 创建 Deployment
118		deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
119		if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
120			return nil, NewResourceError("Deployment", request.Name, "create", err)
121		}
122	
123		// 3. 创建 Service
124		service := generateDevMachineService(request)
125		if err := s.k8sClient.CreateService(ctx, service); err != nil {
126			return nil, NewResourceError("Service", request.Name+serviceSuffix, "create", err)
127		}
128	
129		// 4. 创建 Ingress
130		ingress := generateDevMachineIngress(request)
131		if err := s.k8sClient.CreateIngress(ctx, ingress); err != nil {
132			return nil, NewResourceError("Ingress", request.Name+ingressSuffix, "create", err)
133		}
134	
135		return &devmachinemodel.CreateDevmachineResponse{
136			Name:         request.Name,
137			Status:       devmachinemodel.StageStatusInProgress,
138			CurrentStage: devmachinemodel.StatusScheduling,
139			StartupFlow:  devmachinemodel.GetStartupFlow(),
140			WebUrl:       fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(request.Namespace, request.Name)),
141		}, nil
142	}
