208	func (s *service) DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error) {
209		// 1. 删除 Ingress
210		if err := s.k8sClient.DeleteIngress(ctx, namespace, name+ingressSuffix); err != nil {
211			// 记录错误但继续删除其他资源
212			log.Printf("warning: failed to delete ingress: %v\n", err)
213		}
214	
215		// 2. 删除 Service
216		if err := s.k8sClient.DeleteService(ctx, namespace, name+serviceSuffix); err != nil {
217			log.Printf("warning: failed to delete service: %v\n", err)
218		}
219	
220		// 3. 删除 Deployment
221		if err := s.k8sClient.DeleteDeployment(ctx, namespace, name); err != nil {
222			log.Printf("warning: failed to delete deployment: %v\n", err)
223		}
224	
225		// PVC 和 PV 为共享资源，随 namespace 生命周期管理，不随开发机删除
226	
227		// 返回删除时间
228		return &devmachinemodel.DeleteDevmachineResponse{
229			DeleteAt: time.Now().Format(time.RFC3339),
230		}, nil
