353	// resolveStatus 查询 Pod 并推导开发机当前所处的生命周期状态，供 GetDevmachine 和 GetDevmachineStatus 共用
354	func (s *service) resolveStatus(ctx context.Context, namespace string, deployment *appsv1.Deployment) (status, currentStage, reason string, ready bool, podName string) {
355		// 副本数为 0，开发机已停止
356		if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
357			return "", "", "stopped", false, ""
358		}
359	
360		// 通过 Deployment 的标签选择器查询对应的 Pod
361		if deployment.Spec.Selector == nil {
362			return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusScheduling, "", false, ""
363		}
364		pods, err := s.k8sClient.GetPodsByLabelSelector(ctx, namespace, deployment.Spec.Selector.MatchLabels)
365		if err != nil || len(pods) == 0 {
366			// Pod 尚未创建（Deployment 刚下发，controller 还未生成 Pod）
367			return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusScheduling, "", false, ""
368		}
369	
370		// 取最新创建的 Pod 作为当前状态来源
371		pod := getLatestPod(pods)
372		status, currentStage, reason, ready = getStatusFromPod(pod)
373		return status, currentStage, reason, ready, pod.Name
374	}
