376	func (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
377		// 如果没有指定任何devmachine，则返回空列表
378		if len(devmachines) == 0 {
379			return []devmachinemodel.Devmachine{}, nil
380		}
381	
382		// 初始化结果切片
383		results := make([]devmachinemodel.Devmachine, len(devmachines))
384		errors := make([]error, len(devmachines))
385	
386		// 定义工作函数
387		workerFunc := func(piece int) {
388			// 获取指定的devmachine
389			devmachine := devmachines[piece]
390			// 调用GetDevmachine获取详细信息
391			result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
392			if err != nil {
393				errors[piece] = err
394			} else {
395				results[piece] = result.Devmachine
396			}
397		}
398	
399		// 使用workqueue.ParallelizeUntil进行并行处理
400		// 限制最大并发数以避免对k8s API服务器造成过大压力
401		maxWorkers := 10
402		workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)
403	
404		// 收集成功的结果
405		var successfulResults []devmachinemodel.Devmachine
406		for i, err := range errors {
407			if err == nil {
408				successfulResults = append(successfulResults, results[i])
409			} else {
410				log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
411			}
412		}
413	
414		return successfulResults, nil
415	}
