489	// getLatestPod 从多个 Pod 中取创建时间最晚的一个（滚动更新时可能存在多个 Pod）
490	func getLatestPod(pods []*corev1.Pod) *corev1.Pod {
491		latest := pods[0]
492		for _, pod := range pods[1:] {
493			if pod.CreationTimestamp.After(latest.CreationTimestamp.Time) {
494				latest = pod
495			}
496		}
497		return latest
498	}
499	
500	// getStatusFromPod 根据 Pod 的实时状态推导开发机启动阶段状态
501	func getStatusFromPod(pod *corev1.Pod) (status, currentStage, reason string, ready bool) {
502		// Pod 正在被删除
503		if pod.DeletionTimestamp != nil {
504			return "", "", "terminating", false
505		}
506	
507		switch pod.Status.Phase {
508		case corev1.PodPending:
509			return getPendingStatusDetail(pod)
510		case corev1.PodRunning:
511			return getRunningStatusDetail(pod)
512		case corev1.PodFailed:
513			return devmachinemodel.StageStatusFailed, inferFailureStage(pod),
514				formatReason(pod.Status.Reason, pod.Status.Message), false
515		case corev1.PodSucceeded:
516			return "", "", "stopped", false
517		default:
518			return "", "", "unknown", false
519		}
520	}
521	
522	// getPendingStatusDetail 细化 Pending 阶段的具体状态
523	func getPendingStatusDetail(pod *corev1.Pod) (status, currentStage, reason string, ready bool) {
524		// 1. 检查是否已完成调度
525		for _, cond := range pod.Status.Conditions {
526			if cond.Type == corev1.PodScheduled && cond.Status != corev1.ConditionTrue {
527				return devmachinemodel.StageStatusFailed, devmachinemodel.StatusScheduling,
528					formatReason(cond.Reason, cond.Message), false
529			}
530		}
531	
532		// 2. 检查 Init 容器状态（Init 容器按序执行，逐个检查）
533		for _, cs := range pod.Status.InitContainerStatuses {
534			if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
535				return devmachinemodel.StageStatusFailed, devmachinemodel.StatusInitializing,
536					formatReason(cs.State.Terminated.Reason, fmt.Sprintf("Init容器 %s 执行失败: %s", cs.Name, cs.State.Terminated.Message)), false
537			}
538			if cs.State.Running != nil {
539				return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusInitializing, "", false
540			}
541			if cs.State.Waiting != nil {
542				r := cs.State.Waiting.Reason
543				switch r {
544				case "ErrImagePull", "ImagePullBackOff":
545					return devmachinemodel.StageStatusFailed, devmachinemodel.StatusInitializing,
546						formatReason(r, fmt.Sprintf("Init容器 %s 镜像拉取失败: %s", cs.Name, cs.State.Waiting.Message)), false
547				default:
548					return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusInitializing, "", false
549				}
550			}
551		}
552	
553		// 3. 检查主容器状态
554		for _, cs := range pod.Status.ContainerStatuses {
555			if cs.State.Waiting != nil {
556				r := cs.State.Waiting.Reason
557				switch r {
558				case "ErrImagePull", "ImagePullBackOff":
559					return devmachinemodel.StageStatusFailed, devmachinemodel.StatusPullingImage,
560						formatReason(r, cs.State.Waiting.Message), false
561				case "CrashLoopBackOff":
562					return devmachinemodel.StageStatusFailed, devmachinemodel.StatusStarting,
563						formatReason(r, "容器反复崩溃重启"), false
564				case "ContainerCreating":
565					return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusStarting, "", false
566				default:
567					return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusStarting, "", false
568				}
569			}
570		}
571	
572		// 已调度但尚无容器状态，说明还在拉取镜像
573		return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusPullingImage, "", false
574	}
575	
576	// getRunningStatusDetail 细化 Running 阶段的具体状态（容器可能还未 Ready）
577	func getRunningStatusDetail(pod *corev1.Pod) (status, currentStage, reason string, ready bool) {
578		for _, cs := range pod.Status.ContainerStatuses {
579			if cs.State.Waiting != nil {
580				r := cs.State.Waiting.Reason
581				if r == "CrashLoopBackOff" {
582					return devmachinemodel.StageStatusFailed, devmachinemodel.StatusStarting,
583						formatReason(r, "容器反复崩溃重启"), false
584				}
585				return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusStarting, "", false
586			}
587			if cs.State.Terminated != nil {
588				r := cs.State.Terminated.Reason
589				if r == "OOMKilled" {
590					return devmachinemodel.StageStatusFailed, devmachinemodel.StatusStarting,
591						formatReason(r, "容器内存不足被终止 (OOMKilled)"), false
592				}
593				return devmachinemodel.StageStatusFailed, devmachinemodel.StatusStarting,
594					formatReason(r, cs.State.Terminated.Message), false
595			}
596			if !cs.Ready {
597				return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusStarting, "", false
598			}
599		}
600		if len(pod.Status.ContainerStatuses) == 0 {
601			return devmachinemodel.StageStatusInProgress, devmachinemodel.StatusStarting, "", false
602		}
603		return devmachinemodel.StageStatusSucceed, devmachinemodel.StatusRunning, "", true
604	}
605	
606	func inferFailureStage(pod *corev1.Pod) string {
607		for _, cs := range pod.Status.InitContainerStatuses {
608			if cs.State.Terminated != nil || cs.State.Waiting != nil || cs.State.Running != nil {
609				return devmachinemodel.StatusInitializing
610			}
611		}
612	
613		for _, cs := range pod.Status.ContainerStatuses {
614			if cs.State.Waiting != nil {
615				switch cs.State.Waiting.Reason {
616				case "ErrImagePull", "ImagePullBackOff":
617					return devmachinemodel.StatusPullingImage
618				default:
619					return devmachinemodel.StatusStarting
620				}
621			}
622			if cs.State.Terminated != nil || cs.State.Running != nil {
623				return devmachinemodel.StatusStarting
624			}
625		}
626	
627		return ""
628	}
629	
630	func formatReason(reason, detail string) string {
631		switch {
632		case reason == "" && detail == "":
633			return ""
634		case reason == "":
635			return detail
636		case detail == "":
637			return reason
638		default:
639			return fmt.Sprintf("%s: %s", reason, detail)
640		}
641	}
642	
643	// sharedRWPVName 返回 namespace 级别读写 PV 的名称
644	func sharedRWPVName(namespace string) string {
645		return "shared-rw-pv-" + namespace
646	}
647	
648	// sharedROPVName 返回 namespace 级别只读 PV 的名称
649	func sharedROPVName(namespace string) string {
650		return "shared-ro-pv-" + namespace
651	}
652	
653	// ensureSharedPVCs 兼容兜底：确保 namespace 下共享 PV+PVC 存在（历史 namespace 补建）
654	// TODO: 新环境稳定后可移除
655	func (s *service) ensureSharedPVCs(ctx context.Context, namespace string, storages []devmachinemodel.Storage) error {
656		needsRW, needsRO := false, false
657		for _, st := range storages {
658			if st.ReadOnly {
659				needsRO = true
660			} else {
661				needsRW = true
662			}
663		}
664	
665		if needsRW {
666			if err := s.ensurePVCExists(ctx, namespace, SharedRWPVCName, sharedRWPVName(namespace), false); err != nil {
667				return err
668			}
669		}
670		if needsRO {
671			if err := s.ensurePVCExists(ctx, namespace, SharedROPVCName, sharedROPVName(namespace), true); err != nil {
672				return err
673			}
674		}
675		return nil
676	}
677	
678	// ensurePVCExists 检查 PVC 是否存在，不存在则先创建对应 PV 再创建 PVC
679	func (s *service) ensurePVCExists(ctx context.Context, namespace, pvcName, pvName string, readOnly bool) error {
680		exists, err := s.k8sClient.PVCExists(ctx, namespace, pvcName)
681		if err != nil {
682			return fmt.Errorf("check PVC %s/%s: %w", namespace, pvcName, err)
683		}
684		if !exists {
685			pvExists, err := s.k8sClient.PVExists(ctx, pvName)
686			if err != nil {
687				return fmt.Errorf("check PV %s: %w", pvName, err)
688			}
689			if !pvExists {
690				log.Printf("[compat] shared PV %s not found, creating...", pvName)
691				pv, err := buildSharedPV(pvName, namespace, readOnly)
692				if err != nil {
693					return fmt.Errorf("build PV %s: %w", pvName, err)
694				}
695				if err := s.k8sClient.CreatePV(ctx, pv); err != nil {
696					return fmt.Errorf("create PV %s: %w", pvName, err)
697				}
698			}
699			log.Printf("[compat] shared PVC %s not found in namespace %s, creating...", pvcName, namespace)
700			return s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, pvcName, pvName, readOnly))
701		}
702		return nil
703	}
704	
705	// createSharedPVCs 为 namespace 创建专属的读写和只读 PV+PVC
706	func (s *service) createSharedPVCs(ctx context.Context, namespace string) error {
707		rwPVName := sharedRWPVName(namespace)
708		rwPV, err := buildSharedPV(rwPVName, namespace, false)
709		if err != nil {
710			return fmt.Errorf("build shared-rw-pv for %s: %w", namespace, err)
711		}
712		if err := s.k8sClient.CreatePV(ctx, rwPV); err != nil {
713			return fmt.Errorf("create shared-rw-pv for %s: %w", namespace, err)
714		}
715		if err := s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, SharedRWPVCName, rwPVName, false)); err != nil {
716			return fmt.Errorf("create shared-rw-pvc in %s: %w", namespace, err)
717		}
718	
719		roPVName := sharedROPVName(namespace)
720		roPV, err := buildSharedPV(roPVName, namespace, true)
721		if err != nil {
722			return fmt.Errorf("build shared-ro-pv for %s: %w", namespace, err)
723		}
724		if err := s.k8sClient.CreatePV(ctx, roPV); err != nil {
725			return fmt.Errorf("create shared-ro-pv for %s: %w", namespace, err)
726		}
727		if err := s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, SharedROPVCName, roPVName, true)); err != nil {
728			return fmt.Errorf("create shared-ro-pvc in %s: %w", namespace, err)
729		}
730	
731		return nil
732	}
733	
734	func (s *service) CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error) {
735		// 验证请求参数
736		if request.Namespace == "" {
737			return nil, NewValidationError("namespace", request.Namespace, fmt.Errorf("namespace cannot be empty"))
738		}
739	
740		// 创建命名空间
741		if err := s.k8sClient.CreateNamespace(ctx, request.Namespace); err != nil {
742			return nil, NewResourceError("Namespace", request.Namespace, "create", err)
743		}
744	
745		// 为新 namespace 创建共享 PVC
746		if err := s.createSharedPVCs(ctx, request.Namespace); err != nil {
747			log.Printf("warning: failed to create shared PVCs in namespace %s: %v", request.Namespace, err)
748			// 注意：PVC 创建失败不影响 namespace 创建的成功响应，兼容兜底会在首次创建开发机时补建
749		}
750	
751		return &devmachinemodel.CreateNamespaceResponse{
752			Message: fmt.Sprintf("namespace %s created successfully", request.Namespace),
753		}, nil
754	}
