}

// buildVSCodeVolumeMounts 构建 VSCode 卷挂载
func buildVSCodeVolumeMounts() []corev1.VolumeMount {
	return []corev1.VolumeMount{
		{
			Name:      devVolumeName,
			MountPath: "/opt/dev",
		},
	}
}

// buildVSCodePorts 构建 VSCode 端口
func buildVSCodePorts() []corev1.ContainerPort {
	return []corev1.ContainerPort{
		{
			ContainerPort: vscodePort,
		},
	}
}

// buildLivenessProbe 构建 探针
func buildVscodeProbe() *corev1.Probe {
	return &corev1.Probe{
		ProbeHandler: corev1.ProbeHandler{
			HTTPGet: &corev1.HTTPGetAction{
				Path: "/", // 健康检查端点
				Port: intstr.FromInt(vscodePort),
			},
		},
		InitialDelaySeconds: 5,  // 容器启动后5秒开始检查
		PeriodSeconds:       5,  // 每5秒检查一次
		TimeoutSeconds:      5,  // 超时时间5秒
		SuccessThreshold:    1,  // 成功阈值
		FailureThreshold:    10, // 失败阈值
	}
}

// buildReadynessProbe 构建 探针
func buildJupyterProbe() *corev1.Probe {
	return &corev1.Probe{
		ProbeHandler: corev1.ProbeHandler{
			TCPSocket: &corev1.TCPSocketAction{
				Port: intstr.FromInt(jupyterPort),
			},
		},
		InitialDelaySeconds: 5,  // 容器启动后5秒开始检查
		PeriodSeconds:       5,  // 每5秒检查一次
		TimeoutSeconds:      5,  // 超时时间5秒
		SuccessThreshold:    1,  // 成功阈值
		FailureThreshold:    10, // 失败阈值
	}
}

// buildInitContainerCommand 构建 initContainer 启动命令
func buildInitContainerCommand() []string {
	// 使用脚本启动模式
	initContainerCmd := `set -euo pipefail
echo "[user] DEV_MODE=${DEV_MODE}"
exec /opt/dev/scripts/start-${DEV_MODE}.sh`

	return []string{"bash", "-c", initContainerCmd}
}

// buildUserContainerCommand 构建 userContainer 启动命令
func buildUserContainerCommand() []string {
	userContainerCmd := `set -euo pipefail
echo "[user] DEV_MODE=${DEV_MODE}"
exec /opt/dev/scripts/start-${DEV_MODE}.sh`

	return []string{"bash", "-c", userContainerCmd}
}

func resolveWorkDir(workDir string) string {
	if strings.TrimSpace(workDir) == "" {
		return defaultWorkDir
	}

	return workDir
}

// BuildResourceRequirements 构建资源请求和限制
func BuildResourceRequirements(cpu, memory, gpu, gpuName string) corev1.ResourceRequirements {
	requests := corev1.ResourceList{}
	limits := corev1.ResourceList{}

	// 设置 CPU 请求
	if cpu != "" {
		cpuQuantity, err := resource.ParseQuantity(cpu + "") // 用户传入的数值，单位为核
		if err == nil {
			requests[corev1.ResourceCPU] = cpuQuantity
			limits[corev1.ResourceCPU] = cpuQuantity
		}
	}

	// 设置内存请求
	if memory != "" {
		memoryQuantity, err := resource.ParseQuantity(memory + "Gi") // 用户传入的数值，单位为Gi
		if err == nil {
			requests[corev1.ResourceMemory] = memoryQuantity
			limits[corev1.ResourceMemory] = memoryQuantity
		}
	}

	// 设置 GPU 请求
	if gpu != "" && gpuName != "" {
		gpuQuantity, err := resource.ParseQuantity(gpu) // GPU 数量
		if err == nil {
			// 检查 GPU 是否为虚拟化类型
			if resourcesvc.IsGPUResource(gpuName) && resourcesvc.GetGPUType(gpuName) == resourcesvc.GPUCardTypeVirtual {
				// 如果是虚拟化 GPU，需要特殊处理
				requests[corev1.ResourceName(gpuName)] = gpuQuantity
				limits[corev1.ResourceName(gpuName)] = gpuQuantity
				//

			} else {
				// 如果是整卡 GPU，直接设置
				requests[corev1.ResourceName(gpuName)] = gpuQuantity
				limits[corev1.ResourceName(gpuName)] = gpuQuantity
			}
		}
	}

	return corev1.ResourceRequirements{
		Requests: requests,
		Limits:   limits,
	}
}

// ==================== Service 构建 ====================

// generateDevMachineService 生成开发机 Service
func generateDevMachineService(request *devmachinemodel.CreateDevmachineRequest) *corev1.Service {
	labels := generateLabels(request.Namespace, request.Name, request.Labels)
	port := getServicePort(request.WebIDE)

	service := &corev1.Service{
		ObjectMeta: metav1.ObjectMeta{
			Name:      request.Name + serviceSuffix,
			Namespace: request.Namespace,
			Labels:    labels,
		},
		Spec: corev1.ServiceSpec{
			Selector: labels,
			Type:     corev1.ServiceTypeClusterIP,
			Ports:    buildServicePorts(port),
		},
	}

	return service
}

// getServicePort 根据 WebIDE 类型获取服务端口
func getServicePort(webIDE devmachinemodel.WebIDEType) int32 {
	switch webIDE {
	case devmachinemodel.WebIDEVSCode:
		return vscodePort
	case devmachinemodel.WebIDEJupyter:
		fallthrough
	default:
		return jupyterPort
	}
}

// buildServicePorts 构建服务端口
func buildServicePorts(port int32) []corev1.ServicePort {
	return []corev1.ServicePort{
		{
			Name:       "http",
			Port:       port,
			TargetPort: intstr.FromInt(int(port)),
		},
	}
}

// ==================== Ingress 构建 ====================

// generateDevMachineIngress 生成开发机 Ingress
func generateDevMachineIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
	webIDE := request.WebIDE
	if webIDE == "" {
		webIDE = devmachinemodel.WebIDEJupyter
	}

	if webIDE == devmachinemodel.WebIDEVSCode {
		return generateVSCodeIngress(request)
	}
	ing := generateJupyterIngress(request)
	log.Infof("finish to create devmachine ingress: %s", util.JsonOutPut(ing))
	return ing
}

// generateVSCodeIngress 生成 VSCode Ingress
func generateVSCodeIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
	labels := generateLabels(request.Namespace, request.Name, request.Labels)
	port := getServicePort(devmachinemodel.WebIDEVSCode)
	basePath := buildIngressPath(request.Namespace, request.Name)
	path := fmt.Sprintf("%s(/|$)(.*)", basePath)

	annotations := defaultAnnotations
	annotations[devmachinemodel.RewriteTarget] = "/$2"

	ingress := &networkingv1.Ingress{
		ObjectMeta: metav1.ObjectMeta{
			Name:        request.Name + ingressSuffix,
			Namespace:   request.Namespace,
			Labels:      labels,
			Annotations: annotations,
		},
		Spec: buildIngressSpec(request.Name+serviceSuffix, path, port),
	}

	return ingress
}

// generateJupyterIngress 生成 Jupyter Ingress
func generateJupyterIngress(request *devmachinemodel.CreateDevmachineRequest) *networkingv1.Ingress {
	labels := generateLabels(request.Namespace, request.Name, request.Labels)
	port := getServicePort(devmachinemodel.WebIDEJupyter)
	path := buildIngressPath(request.Namespace, request.Name)

	annotations := defaultAnnotations
	// 先检查 key 是否存在
	if _, exists := annotations["nginx.ingress.kubernetes.io/rewrite-target"]; exists {
		delete(annotations, devmachinemodel.RewriteTarget)
		fmt.Println("can get this key:", devmachinemodel.RewriteTarget)
	} else {
		fmt.Println("not found this anno:", devmachinemodel.RewriteTarget)
	}
	ingress := &networkingv1.Ingress{
		ObjectMeta: metav1.ObjectMeta{
			Name:        request.Name + ingressSuffix,
			Namespace:   request.Namespace,
			Labels:      labels,
			Annotations: annotations,
		},
		Spec: buildIngressSpec(request.Name+serviceSuffix, path, port),
	}

	return ingress
}

// buildIngressPath 构建 Ingress 路径
func buildIngressPath(namespace, name string) string {
	return fmt.Sprintf("/%s-%s", namespace, name)
}

// buildIngressSpec 构建 Ingress 规范
func buildIngressSpec(serviceName, path string, port int32) networkingv1.IngressSpec {
	return networkingv1.IngressSpec{
		IngressClassName: ptr.To("nginx"),
		Rules:            buildIngressRules(serviceName, path, port),
	}
}

// buildIngressRules 构建 Ingress 规则
func buildIngressRules(serviceName, path string, port int32) []networkingv1.IngressRule {
	return []networkingv1.IngressRule{
		{
			IngressRuleValue: buildIngressRuleValue(serviceName, path, port),
		},
	}
}

// buildIngressRuleValue 构建 Ingress 规则值
func buildIngressRuleValue(serviceName, path string, port int32) networkingv1.IngressRuleValue {
	return networkingv1.IngressRuleValue{
		HTTP: &networkingv1.HTTPIngressRuleValue{
			Paths: buildIngressPaths(serviceName, path, port),
		},
	}
}

// buildIngressPaths 构建 Ingress 路径列表
func buildIngressPaths(serviceName, path string, port int32) []networkingv1.HTTPIngressPath {
	pathTypePrefix := networkingv1.PathTypePrefix

	return []networkingv1.HTTPIngressPath{
		{
			Path:     path,
			PathType: &pathTypePrefix,
			Backend:  buildIngressBackend(serviceName, port),
		},
	}
}

// buildIngressBackend 构建 Ingress 后端
func buildIngressBackend(serviceName string, port int32) networkingv1.IngressBackend {
	return networkingv1.IngressBackend{
		Service: &networkingv1.IngressServiceBackend{
			Name: serviceName,
			Port: networkingv1.ServiceBackendPort{
				Number: port,
			},
		},
	}
}

// ==================== 辅助函数 ====================

// generateLabels 生成标签
func generateLabels(namespace, name string, labels map[string]string) map[string]string {
	if labels == nil {
		labels = make(map[string]string)
	}
	labels["app"] = fmt.Sprintf(devMachineName, namespace, name)
	return labels
}

// generateAnnotations 生成注解
func generateAnnotations(queue string, annotations map[string]string) map[string]string {
	if annotations == nil {
		annotations = make(map[string]string)
	}
	annotations[volcanoQueueName] = queue
	return annotations
}

