		Command:         buildUserContainerCommand(),
		LivenessProbe:   buildVscodeProbe(),
		ReadinessProbe:  buildVscodeProbe(),
	}

	// 设置资源请求和限制
	container.Resources = BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)

	return container
}

