// ==================== Deployment 构建 ====================

// generateDevMachineDeployment 生成开发机 Deployment
func generateDevMachineDeployment(request *devmachinemodel.CreateDevmachineRequest, initContainerImage string) *appsv1.Deployment {
	labels := generateLabels(request.Namespace, request.Name, request.Labels)
	annotations := generateAnnotations(request.QueueName, request.Annotations)

	deployment := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{
			Name:        request.Name,
			Namespace:   request.Namespace,
			Labels:      labels,
			Annotations: annotations,
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: ptr.To[int32](1),
			Selector: &metav1.LabelSelector{
				MatchLabels: labels,
			},
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels:      labels,
					Annotations: annotations,
				},
				Spec: buildPodSpec(request, initContainerImage),
			},
		},
	}

	return deployment
}

// buildPodSpec 构建 Pod 规范
func buildPodSpec(request *devmachinemodel.CreateDevmachineRequest, initContainerImage string) corev1.PodSpec {
	webIDE := request.WebIDE
	if webIDE == "" {
		webIDE = devmachinemodel.WebIDEJupyter
	}

	// 构建基础卷（emptyDir）
	volumes := buildVolumes(webIDE)

	// 添加共享存储卷（按 ReadOnly 去重，最多 2 个）
	storageVolumes := buildSharedVolumes(request.Storage)
	volumes = append(volumes, storageVolumes...)

	return corev1.PodSpec{
		SchedulerName:  volcanoSchedulerName,
		NodeSelector:   request.NodeSelector,
		Volumes:        volumes,
		InitContainers: buildInitContainers(initContainerImage, webIDE),
		Containers:     buildContainers(request),
	}
}

// ==================== Volume 构建 ====================

// buildVolumes 构建存储卷
func buildVolumes(webIDE devmachinemodel.WebIDEType) []corev1.Volume {
	// 基础卷（所有类型共享）
	volumes := []corev1.Volume{
		{
			Name: devVolumeName,
			VolumeSource: corev1.VolumeSource{
				EmptyDir: &corev1.EmptyDirVolumeSource{},
			},
		},
	}

	// Jupyter 需要额外的 bootstrap-jupyter emptyDir
	if webIDE == devmachinemodel.WebIDEJupyter {
		volumes = append(volumes, corev1.Volume{
			Name: bootstrapJupyterVolumeName,
			VolumeSource: corev1.VolumeSource{
				EmptyDir: &corev1.EmptyDirVolumeSource{},
			},
		})
	}

	return volumes
}

