	// 构建基础卷挂载
	volumeMounts := buildJupyterVolumeMounts()

	// 添加共享存储卷挂载（subPath 隔离）
	storageVolumeMounts := buildSharedVolumeMounts(request.Storage)
	volumeMounts = append(volumeMounts, storageVolumeMounts...)

	container := corev1.Container{
		Name:            "jupyter",
		Image:           request.ImageName,
		ImagePullPolicy: corev1.PullIfNotPresent,
		Env:             buildJupyterEnv(request.WorkDir, request.Storage),
		VolumeMounts:    volumeMounts,
		Ports:           buildJupyterPorts(),
